import{_ as n,C as r,o as t,c as s,a2 as o,b as l,w as i,a as d,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const x=JSON.parse('{"title":"Summary","description":"Recap of the extensibility and plugins chapter, reviewing the plugin architecture, MCP integration, and how extensibility transforms the agent into a platform.","frontmatter":{"title":"Summary","description":"Recap of the extensibility and plugins chapter, reviewing the plugin architecture, MCP integration, and how extensibility transforms the agent into a platform."},"headers":[],"relativePath":"learn/project/14-extensibility-and-plugins/14-summary.md","filePath":"learn/project/14-extensibility-and-plugins/14-summary.md"}'),u={name:"learn/project/14-extensibility-and-plugins/14-summary.md"};function g(p,e,m,f,y,b){const a=r("Mermaid");return t(),s("div",null,[e[1]||(e[1]=o('<h1 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How all extensibility mechanisms -- plugins, events, hooks, MCP, skills -- form a cohesive platform</li><li>Which extension patterns provide the highest value for the least implementation complexity</li><li>How to evolve the plugin system as the agent and its community grow</li></ul></blockquote><p>This chapter transformed your coding agent from a closed application into an extensible platform. You started with a monolithic agent where every capability was compiled in, and you built the infrastructure that lets anyone -- including people who do not write Rust -- add tools, modify behavior, and connect external systems. Let&#39;s review what you built and how the pieces fit together.</p><h2 id="the-extension-architecture-at-a-glance" tabindex="-1">The Extension Architecture at a Glance <a class="header-anchor" href="#the-extension-architecture-at-a-glance" aria-label="Permalink to &quot;The Extension Architecture at a Glance&quot;">​</a></h2><p>Here is a summary of every extension mechanism you implemented and where it fits:</p>',5)),(t(),l(h,null,{default:i(()=>[c(a,{id:"mermaid-34",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20INPUT%5B%22User%20Input%22%5D%0A%20%20%20%20%20%20%20%20CHAT%5B%22Chat%20Message%22%5D%0A%20%20%20%20%20%20%20%20CMD%5B%22%2Fcommand%22%5D%0A%20%20%20%20%20%20%20%20CONFIN%5B%22Config%20File%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20CORE%5B%22Agent%20Core%22%5D%0A%20%20%20%20%20%20%20%20PM%5B%22Plugin%20Manager%5CnPlugin%20A%2C%20Plugin%20B%22%5D%0A%20%20%20%20%20%20%20%20EB%5B%22Event%20Bus%5CnHandlers%22%5D%0A%20%20%20%20%20%20%20%20CL%5B%22Config%20Loader%22%5D%0A%20%20%20%20%20%20%20%20TR%5B%22Tool%20Registry%5Cndynamic%22%5D%0A%20%20%20%20%20%20%20%20HR%5B%22Hook%20Registry%5Cnpre%2Fpost%22%5D%0A%20%20%20%20%20%20%20%20CR%5B%22Command%20Registry%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20EXT%5B%22External%20Connections%22%5D%0A%20%20%20%20%20%20%20%20MCP%5B%22MCP%20Servers%5Cnstdio%2FHTTP%22%5D%0A%20%20%20%20%20%20%20%20SKILL%5B%22Skill%20Loader%22%5D%0A%20%20%20%20%20%20%20%20HOT%5B%22Hot%20Reload%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20CHAT%20%26%20CMD%20%26%20CONFIN%20--%3E%20CORE%0A%20%20%20%20TR%20--%3E%20EXT%0A%20%20%20%20HR%20--%3E%20EXT%0A%20%20%20%20CR%20--%3E%20EXT%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="what-you-built" tabindex="-1">What You Built <a class="header-anchor" href="#what-you-built" aria-label="Permalink to &quot;What You Built&quot;">​</a></h2><h3 id="core-infrastructure" tabindex="-1">Core Infrastructure <a class="header-anchor" href="#core-infrastructure" aria-label="Permalink to &quot;Core Infrastructure&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th><th>Key Type</th></tr></thead><tbody><tr><td><strong>Plugin Architecture</strong></td><td>Lifecycle management, dependency resolution, extension points</td><td><code>Plugin</code> trait, <code>PluginManager</code></td></tr><tr><td><strong>Tool Registry</strong></td><td>Dynamic tool registration with schema validation and conflict resolution</td><td><code>ToolRegistry</code>, <code>ToolHandler</code></td></tr><tr><td><strong>Event Bus</strong></td><td>Pub-sub event system for agent lifecycle notifications</td><td><code>EventBus</code>, <code>AgentEvent</code></td></tr><tr><td><strong>Hook Registry</strong></td><td>Synchronous interception points for modifying or vetoing operations</td><td><code>HookRegistry</code>, <code>HookAction</code></td></tr></tbody></table><h3 id="protocol-and-integration" tabindex="-1">Protocol and Integration <a class="header-anchor" href="#protocol-and-integration" aria-label="Permalink to &quot;Protocol and Integration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th><th>Key Type</th></tr></thead><tbody><tr><td><strong>MCP Client</strong></td><td>Connect to external tool servers via the Model Context Protocol</td><td><code>McpClient</code>, <code>StdioTransport</code></td></tr><tr><td><strong>MCP Bridge</strong></td><td>Integrate MCP-provided tools into the agent&#39;s tool registry</td><td><code>McpToolBridge</code></td></tr><tr><td><strong>Skill Loader</strong></td><td>Bundle and manage coherent sets of tools, prompts, and config</td><td><code>SkillLoader</code>, <code>SkillDefinition</code></td></tr><tr><td><strong>Command Registry</strong></td><td>User-facing slash commands with argument parsing and tab completion</td><td><code>CommandRegistry</code>, <code>SlashCommand</code> trait</td></tr></tbody></table><h3 id="operations-and-quality" tabindex="-1">Operations and Quality <a class="header-anchor" href="#operations-and-quality" aria-label="Permalink to &quot;Operations and Quality&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th><th>Key Type</th></tr></thead><tbody><tr><td><strong>Config Loader</strong></td><td>Declarative extensions via TOML/JSON without writing code</td><td><code>AgentConfig</code>, <code>ConfigLoader</code></td></tr><tr><td><strong>Hot Reloading</strong></td><td>Watch files for changes and apply them without restart</td><td><code>ReloadManager</code>, <code>FileWatcher</code></td></tr><tr><td><strong>Plugin Isolation</strong></td><td>Fault boundaries, timeouts, and resource tracking</td><td><code>FaultBoundary</code>, <code>ResourceTracker</code></td></tr><tr><td><strong>Test Harness</strong></td><td>Mock environment for plugin developers to test against</td><td><code>PluginTestHarness</code></td></tr></tbody></table><h2 id="the-extension-spectrum" tabindex="-1">The Extension Spectrum <a class="header-anchor" href="#the-extension-spectrum" aria-label="Permalink to &quot;The Extension Spectrum&quot;">​</a></h2><p>Not all extension mechanisms are equally complex or useful. Here they are ordered by implementation effort and practical value:</p><h3 id="high-value-low-effort" tabindex="-1">High Value, Low Effort <a class="header-anchor" href="#high-value-low-effort" aria-label="Permalink to &quot;High Value, Low Effort&quot;">​</a></h3><ol><li><p><strong>Config-driven tools</strong> -- Shell command tools defined in TOML. Users write zero code, and the tools work immediately. This covers the vast majority of simple extensions.</p></li><li><p><strong>MCP servers</strong> -- Point the agent at an existing MCP server and its tools appear automatically. The ecosystem provides dozens of ready-made servers for databases, APIs, and services.</p></li><li><p><strong>System prompt injection</strong> -- CLAUDE.md-style project files that inject context. Simple text files that dramatically improve agent behavior for specific projects.</p></li></ol><h3 id="high-value-medium-effort" tabindex="-1">High Value, Medium Effort <a class="header-anchor" href="#high-value-medium-effort" aria-label="Permalink to &quot;High Value, Medium Effort&quot;">​</a></h3><ol start="4"><li><p><strong>Hook configuration</strong> -- Shell commands that run at lifecycle points. Security checks, audit logging, and custom notifications without compiled code.</p></li><li><p><strong>Skill packages</strong> -- TOML-defined bundles of tools and prompts with context-aware activation. Reusable across projects.</p></li><li><p><strong>Slash commands</strong> -- Direct user actions that bypass the LLM. Essential for agent control (clear context, switch models, check status).</p></li></ol><h3 id="high-value-high-effort" tabindex="-1">High Value, High Effort <a class="header-anchor" href="#high-value-high-effort" aria-label="Permalink to &quot;High Value, High Effort&quot;">​</a></h3><ol start="7"><li><p><strong>Plugin trait implementation</strong> -- Full compiled plugins with access to all registries. Maximum power and performance, but requires Rust.</p></li><li><p><strong>Event system</strong> -- Useful for cross-cutting concerns like metrics and logging, but most plugin developers do not need it directly.</p></li><li><p><strong>Extension marketplace</strong> -- Discovery and distribution infrastructure. Essential at scale, but only worth building after you have an active plugin community.</p></li></ol><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>This spectrum mirrors the Python ecosystem&#39;s evolution. Python started with simple script-based extensions (like config-driven tools), grew to support entry-point-based plugins (like the Plugin trait), and eventually built PyPI for distribution (like the marketplace). The lesson: start simple and add complexity only when the simpler approaches are insufficient. Most users will never need the full Plugin trait -- config-driven tools and MCP servers cover 90% of real-world needs.</p></div><h2 id="how-production-agents-approach-extensibility" tabindex="-1">How Production Agents Approach Extensibility <a class="header-anchor" href="#how-production-agents-approach-extensibility" aria-label="Permalink to &quot;How Production Agents Approach Extensibility&quot;">​</a></h2><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Production coding agents take pragmatic approaches to extensibility:</p><p><strong>Claude Code</strong> focuses on three mechanisms: MCP servers for tool extensibility, hooks (shell commands at lifecycle points) for behavior modification, and CLAUDE.md files for project-specific prompting. This covers the high-value, low-effort quadrant. There is no formal plugin API or marketplace -- the focus is on mechanisms that non-developers can use.</p><p><strong>OpenCode</strong> provides MCP support and a clean tool interface, making it straightforward to add tools by implementing the Tool interface in Go. It does not have a hook system or marketplace -- extensibility comes through code contributions and MCP servers.</p><p>The trend is clear: MCP is becoming the universal extension mechanism. Rather than each agent defining its own plugin format, the community is converging on MCP as the shared interface. Write an MCP server once, and it works with every compatible agent.</p></div><h2 id="evolving-the-plugin-system" tabindex="-1">Evolving the Plugin System <a class="header-anchor" href="#evolving-the-plugin-system" aria-label="Permalink to &quot;Evolving the Plugin System&quot;">​</a></h2><p>As your agent grows, the extension system will evolve. Here is a practical roadmap:</p><p><strong>Phase 1: Core</strong> (what you built in this chapter)</p><ul><li>Plugin trait and manager</li><li>Tool, event, hook, and command registries</li><li>Config-driven tools and MCP support</li></ul><p><strong>Phase 2: Ecosystem</strong></p><ul><li>Publish a catalog of official MCP server recommendations</li><li>Create a skill package format and share common skills</li><li>Document the plugin API for community developers</li></ul><p><strong>Phase 3: Distribution</strong></p><ul><li>Build or adopt a registry for extension discovery</li><li>Implement install/update commands</li><li>Establish a security review process for community contributions</li></ul><p><strong>Phase 4: Advanced</strong></p><ul><li>WebAssembly-based plugin isolation for untrusted code</li><li>Plugin composition (plugins that extend other plugins)</li><li>Analytics and quality metrics for published extensions</li></ul><h2 id="what-comes-next" tabindex="-1">What Comes Next <a class="header-anchor" href="#what-comes-next" aria-label="Permalink to &quot;What Comes Next&quot;">​</a></h2><p>In <a href="/project/15-production-polish/">Chapter 15: Production Polish</a>, you will take everything you have built -- from the basic REPL in Chapter 1 through the extensible platform in this chapter -- and prepare it for real-world use. You will add logging, error reporting, performance profiling, graceful shutdown, and the polish that separates a prototype from a production tool.</p><p>The extension system you built here is what makes that production transition worthwhile. A polished agent that only does what you built is useful. A polished agent that anyone can extend is a platform.</p><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><p>Practice each concept with these exercises. They build on the extensibility and plugin system you created in this chapter.</p><h3 id="exercise-1-create-a-config-driven-tool-easy" tabindex="-1">Exercise 1: Create a Config-Driven Tool (Easy) <a class="header-anchor" href="#exercise-1-create-a-config-driven-tool-easy" aria-label="Permalink to &quot;Exercise 1: Create a Config-Driven Tool (Easy)&quot;">​</a></h3><p>Define a new tool entirely in TOML configuration (no Rust code). Create a <code>git-status</code> tool that runs <code>git status --short</code> in the project root and returns the output. Add it to your <code>.kodai/tools.toml</code> file, reload the config, and verify it appears in the tool registry and can be invoked by the LLM.</p><ul><li>Define the tool in TOML with <code>name</code>, <code>description</code>, <code>command</code>, and <code>working_dir</code> fields</li><li>Set the <code>input_schema</code> to accept an optional <code>path</code> parameter for checking status of a subdirectory</li><li>Test by sending a message like &quot;What files have changed?&quot; and verifying the agent uses your tool</li></ul><h3 id="exercise-2-add-a-plugins-status-command-easy" tabindex="-1">Exercise 2: Add a /plugins Status Command (Easy) <a class="header-anchor" href="#exercise-2-add-a-plugins-status-command-easy" aria-label="Permalink to &quot;Exercise 2: Add a /plugins Status Command (Easy)&quot;">​</a></h3><p>Implement a <code>/plugins</code> REPL command that lists all loaded plugins with their name, version, status (active/disabled/errored), and the number of tools, hooks, and commands each one registered. Include MCP servers as a separate section showing their connection status.</p><ul><li>Iterate through <code>PluginManager</code>&#39;s loaded plugins and format each entry</li><li>For MCP servers, show the transport type (stdio/HTTP) and connection state</li><li>Display a summary line at the bottom: <code>[4 plugins active, 12 tools, 3 hooks, 2 MCP servers]</code></li></ul><h3 id="exercise-3-implement-a-pre-execution-hook-medium" tabindex="-1">Exercise 3: Implement a Pre-Execution Hook (Medium) <a class="header-anchor" href="#exercise-3-implement-a-pre-execution-hook-medium" aria-label="Permalink to &quot;Exercise 3: Implement a Pre-Execution Hook (Medium)&quot;">​</a></h3><p>Add a hook that runs before every shell command execution. The hook receives the command string and working directory, and can modify the command, allow it unchanged, or block it. Implement a concrete hook that prepends <code>time</code> to every command so the LLM can see execution duration.</p><p><strong>Hints:</strong></p><ul><li>Define the hook point as <code>HookPoint::PreShellExec</code> in the <code>HookRegistry</code></li><li>The hook function signature should be <code>fn(command: &amp;str, cwd: &amp;Path) -&gt; HookAction</code> where <code>HookAction</code> is <code>Allow(String)</code>, <code>PassThrough</code>, or <code>Block(String)</code></li><li>Register the timing hook: it transforms <code>&quot;cargo test&quot;</code> into <code>&quot;time cargo test&quot;</code> by returning <code>HookAction::Allow(format!(&quot;time {}&quot;, command))</code></li><li>Test that blocked hooks return the block reason as a tool error</li></ul><h3 id="exercise-4-build-an-mcp-server-connector-medium" tabindex="-1">Exercise 4: Build an MCP Server Connector (Medium) <a class="header-anchor" href="#exercise-4-build-an-mcp-server-connector-medium" aria-label="Permalink to &quot;Exercise 4: Build an MCP Server Connector (Medium)&quot;">​</a></h3><p>Implement a function that connects to an MCP server via stdio transport, performs the initialization handshake, queries the server&#39;s tool list, and registers those tools in your agent&#39;s <code>ToolRegistry</code>. Test it against a simple MCP server that provides one tool (you can use an existing MCP server or write a minimal one as a script).</p><p><strong>Hints:</strong></p><ul><li>Spawn the MCP server process with <code>tokio::process::Command</code> and piped stdin/stdout</li><li>Send the <code>initialize</code> JSON-RPC message and parse the response to get server capabilities</li><li>Send <code>tools/list</code> to get available tools, then create <code>McpToolBridge</code> instances for each</li><li>Each bridged tool should forward <code>execute()</code> calls as <code>tools/call</code> JSON-RPC messages to the server</li><li>Handle server disconnection gracefully by removing bridged tools from the registry</li></ul><h3 id="exercise-5-build-a-complete-plugin-with-lifecycle-management-hard" tabindex="-1">Exercise 5: Build a Complete Plugin with Lifecycle Management (Hard) <a class="header-anchor" href="#exercise-5-build-a-complete-plugin-with-lifecycle-management-hard" aria-label="Permalink to &quot;Exercise 5: Build a Complete Plugin with Lifecycle Management (Hard)&quot;">​</a></h3><p>Create a full plugin that implements the <code>Plugin</code> trait, registers two custom tools (e.g., <code>http-get</code> for fetching URLs and <code>json-query</code> for extracting values from JSON using a path expression), subscribes to the <code>ToolExecuted</code> event for logging, and supports hot-reloading its configuration. Package it as a separate module that can be loaded at startup.</p><p><strong>Hints:</strong></p><ul><li>Implement all <code>Plugin</code> lifecycle methods: <code>init()</code>, <code>on_load()</code>, <code>on_unload()</code>, <code>name()</code>, <code>version()</code></li><li>In <code>on_load()</code>, register your tools with <code>context.tool_registry.register()</code> and subscribe to events with <code>context.event_bus.subscribe()</code></li><li>The <code>http-get</code> tool should use <code>reqwest::blocking::get()</code> with a timeout; the <code>json-query</code> tool should accept a JSON string and a dot-separated path like <code>&quot;data.users[0].name&quot;</code></li><li>For hot-reloading, watch a config file and call <code>on_unload()</code> then <code>on_load()</code> when it changes, re-registering tools with updated configuration</li><li>Write tests using <code>PluginTestHarness</code> that verify tool registration, execution, event handling, and reload behavior</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>The extensibility system has three tiers: config-driven extensions (no code, highest accessibility), protocol-based extensions (MCP, any language), and compiled plugins (maximum power, Rust only)</li><li>Start with the high-value, low-effort patterns: config-driven tools, MCP servers, and prompt injection cover 90% of real-world extension needs without requiring users to write Rust</li><li>The event bus, hook registry, tool registry, and command registry form the internal extension API surface, connected through <code>Arc&lt;RwLock&lt;_&gt;&gt;</code> for thread-safe concurrent access</li><li>MCP is converging as the universal extension protocol for AI agents -- building MCP support gives your agent access to a growing ecosystem shared across all compatible agents</li><li>Plugin isolation through fault boundaries, resource tracking, and process separation ensures that the agent remains stable even when third-party extensions misbehave</li></ul>',53))])}const P=n(u,[["render",g]]);export{x as __pageData,P as default};
